import { type TgpuRoot } from 'typegpu';
import { modelVertexLayout } from './model-schema';

function decodeBase64ToFloat32(base64: string): ArrayBuffer {
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }

  return bytes.buffer;
}

function decodeModel(root: TgpuRoot, base64: string, polygonCount: number) {
  const floats = decodeBase64ToFloat32(base64);
  const vertexBuffer = root
    .createBuffer(modelVertexLayout.schemaForCount(polygonCount))
    .$usage('vertex');
  vertexBuffer.write(floats);
  return { vertexBuffer, polygonCount };
}

export const models = {
  'stara-zajezdnia-accessories': (root: TgpuRoot) =>
    decodeModel(
      root,
      '',
      42960,
    ),
  'stara-zajezdnia-base': (root: TgpuRoot) =>
    decodeModel(
      root,
      '',
      2820,
    ),
  'stara-zajezdnia-groudplanes': (root: TgpuRoot) =>
    decodeModel(
      root,
      '',
      330,
    ),
  'stara-zajezdnia-guidelines': (root: TgpuRoot) =>
    decodeModel(
      root,
      '',
      960,
    ),
  'stara-zajezdnia-outside': (root: TgpuRoot) =>
    decodeModel(
      root,
      '',
      3126,
    ),
};
